/** Default ChartContainer (`className`) — override `@workspace/ui` chart `aspect-video`; give Recharts a definite box (`min-w-0` avoids grid/flex `-1` measure glitches). */
export const METRICS_CHART_SURFACE_CLASS_DEFAULT =
  "aspect-auto flex h-56 min-h-56 w-full min-w-0 shrink-0 flex-col [&_.recharts-responsive-container]:min-h-[12rem] [&_.recharts-responsive-container]:min-w-0 [&_.recharts-responsive-container]:w-full";

import type { ReactNode } from "react";

export interface MetricDataPoint {
  timestamp: number;
  value: number;
}

export type MetricsData = Record<string, MetricDataPoint[]>;

export interface MetricsChartContextValue {
  chartClassName: string;
  data: MetricsData;
  dataKey?: string;
}

export interface MetricsChartRootProps {
  chartClassName?: string;
  children: ReactNode;
  data: MetricsData;
  dataKey?: string;
}

import { createContext } from "react";

import type { MetricsChartContextValue } from "./metrics-chart.types";

export const MetricsChartContext =
  createContext<MetricsChartContextValue | null>(null);

"use client";

import { use } from "react";

import { MetricsChartContext } from "./metrics-chart.context";

export function useMetricsChart() {
  const ctx = use(MetricsChartContext);
  if (!ctx) {
    throw new Error(
      "useMetricsChart must be used within MetricsChart.Root (or MetricsChartProvider)."
    );
  }
  return ctx;
}

"use client";

import type { ReactNode } from "react";
import { useMemo } from "react";
import { MetricsChartContext } from "./metrics-chart.context";
import { METRICS_CHART_SURFACE_CLASS_DEFAULT } from "./metrics-chart.defaults";
import type { MetricsChartContextValue } from "./metrics-chart.types";

export function MetricsChartProvider({
  children,
  chartClassName,
  data,
  dataKey,
}: {
  children: ReactNode;
  chartClassName?: string;
  data: MetricsChartContextValue["data"];
  dataKey?: string;
}) {
  const value = useMemo<MetricsChartContextValue>(
    () => ({
      chartClassName: chartClassName ?? METRICS_CHART_SURFACE_CLASS_DEFAULT,
      data,
      dataKey,
    }),
    [chartClassName, data, dataKey]
  );

  return <MetricsChartContext value={value}>{children}</MetricsChartContext>;
}

"use client";

import {
  type ChartConfig,
  ChartContainer,
  ChartLegend,
  ChartLegendContent,
  ChartTooltip,
  ChartTooltipContent,
} from "@workspace/ui/components/chart";
import { useMemo } from "react";
import { Area, AreaChart, CartesianGrid, XAxis, YAxis } from "recharts";

import { METRICS_CHART_SURFACE_CLASS_DEFAULT } from "./metrics-chart.defaults";
import type { MetricsData } from "./metrics-chart.types";
import { useMetricsChart } from "./metrics-chart.use";

const CHART_PALETTE = [
  "chart-1",
  "chart-2",
  "chart-3",
  "chart-4",
  "chart-5",
] as const;

const METRIC_KEYS_FOR_COLOR = [
  "cpu",
  "memory",
  "disk",
  "storage",
  "uptime",
] as const;

function formatTimestamp(timestamp: number): string {
  const d = new Date(timestamp * 1000);
  const h = d.getHours();
  const m = d.getMinutes();
  return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`;
}

function capitalizeLabel(key: string): string {
  return key.charAt(0).toUpperCase() + key.slice(1);
}

function getColorForMetricKey(key: string): string {
  const lower = key.toLowerCase();
  const idx = (METRIC_KEYS_FOR_COLOR as readonly string[]).indexOf(lower);
  const paletteKey = CHART_PALETTE[idx >= 0 ? idx % CHART_PALETTE.length : 0];
  return `var(--${paletteKey})`;
}

function mergeMetricsByTimestamp(
  data: MetricsData
): Record<string, number | string>[] {
  const allTimestamps = new Set<number>();
  for (const series of Object.values(data)) {
    for (const point of series) {
      allTimestamps.add(point.timestamp);
    }
  }
  const sorted = Array.from(allTimestamps).sort((a, b) => a - b);
  return sorted.map((timestamp) => {
    const point: Record<string, number | string> = {
      timestamp,
      readableTime: formatTimestamp(timestamp),
    };
    for (const [key, series] of Object.entries(data)) {
      const found = series.find((d) => d.timestamp === timestamp);
      if (found != null) {
        point[key] = found.value;
      }
    }
    return point;
  });
}

export function MetricsChartArea() {
  const { data, dataKey, chartClassName } = useMetricsChart();

  const keys = useMemo(
    () => (dataKey == null ? Object.keys(data) : [dataKey]),
    [data, dataKey]
  );

  const chartData = useMemo(() => {
    if (dataKey != null) {
      const series = data[dataKey];
      if (!series) {
        return [];
      }
      return series.map(({ timestamp, value }) => ({
        timestamp,
        value,
        readableTime: formatTimestamp(timestamp),
      }));
    }
    return mergeMetricsByTimestamp(data);
  }, [data, dataKey]);

  const config = useMemo<ChartConfig>(() => {
    const cfg: ChartConfig = {};
    const configKeys = dataKey == null ? keys : ["value"];
    for (const key of configKeys) {
      const labelKey = dataKey ?? key;
      cfg[key] = {
        color: getColorForMetricKey(labelKey),
        label: capitalizeLabel(labelKey),
      };
    }
    return cfg;
  }, [keys, dataKey]);

  const hasData = chartData.length > 0 && keys.length > 0;
  if (!hasData) {
    return null;
  }

  const areas = dataKey == null ? keys : ["value"];

  const gradientIdFor = (seriesKey: string) => `fill-${dataKey ?? seriesKey}`;

  return (
    <ChartContainer
      className={chartClassName || METRICS_CHART_SURFACE_CLASS_DEFAULT}
      config={config}
    >
      <AreaChart
        data={chartData}
        margin={{ top: 8, right: 8, bottom: 4, left: -30 }}
      >
        <defs>
          {areas.map((seriesKey) => {
            const id = gradientIdFor(seriesKey);
            return (
              <linearGradient id={id} key={id} x1="0" x2="0" y1="0" y2="1">
                <stop
                  offset="5%"
                  stopColor={`var(--color-${seriesKey})`}
                  stopOpacity={0.8}
                />
                <stop
                  offset="95%"
                  stopColor={`var(--color-${seriesKey})`}
                  stopOpacity={0.1}
                />
              </linearGradient>
            );
          })}
        </defs>
        <CartesianGrid vertical={false} />
        <XAxis
          axisLine={false}
          dataKey="readableTime"
          tickFormatter={(v) =>
            typeof v === "string" ? (v.split(" ").at(-1) ?? v) : String(v)
          }
          tickLine={false}
          tickMargin={4}
        />
        <YAxis
          axisLine={false}
          domain={[0, 100]}
          tickLine={false}
          tickMargin={4}
          ticks={[50, 100]}
        />
        <ChartTooltip
          content={
            <ChartTooltipContent
              valueFormatter={(v) => `${Number(v).toFixed(1)}%`}
            />
          }
          trigger="hover"
        />
        <ChartLegend content={<ChartLegendContent />} verticalAlign="bottom" />
        {areas.map((seriesKey) => (
          <Area
            dataKey={seriesKey}
            fill={`url(#${gradientIdFor(seriesKey)})`}
            isAnimationActive={false}
            key={seriesKey}
            stroke={`var(--color-${seriesKey})`}
            type="monotone"
          />
        ))}
      </AreaChart>
    </ChartContainer>
  );
}

"use client";

import { MetricsChartArea } from "./metrics-chart.area";
import { MetricsChartProvider } from "./metrics-chart.provider";
import type { MetricsChartRootProps } from "./metrics-chart.types";

export function MetricsChartRoot({
  chartClassName,
  children,
  data,
  dataKey,
}: MetricsChartRootProps) {
  return (
    <MetricsChartProvider
      chartClassName={chartClassName}
      data={data}
      dataKey={dataKey}
    >
      {children}
    </MetricsChartProvider>
  );
}

export function MetricsChartVariant0({
  chartClassName,
  data,
  dataKey,
}: Omit<MetricsChartRootProps, "children"> & {
  dataKey: string;
}) {
  return (
    <MetricsChartRoot
      chartClassName={chartClassName}
      data={data}
      dataKey={dataKey}
    >
      <MetricsChartArea />
    </MetricsChartRoot>
  );
}

export function MetricsChartVariant1({
  chartClassName,
  data,
}: Omit<MetricsChartRootProps, "children">) {
  return (
    <MetricsChartRoot chartClassName={chartClassName} data={data}>
      <MetricsChartArea />
    </MetricsChartRoot>
  );
}

export const MetricsChart = {
  Area: MetricsChartArea,
  Root: MetricsChartRoot,
  Variant0: MetricsChartVariant0,
  Variant1: MetricsChartVariant1,
};

export type {
  MetricDataPoint,
  MetricsChartContextValue,
  MetricsChartRootProps,
  MetricsData,
} from "./metrics-chart.types";

// biome-ignore lint/performance/noBarrelFile: re-export for `import { useMetricsChart } from …/metrics-chart`
export { useMetricsChart } from "./metrics-chart.use";
